<?php
session_start();
require 'db.php';

if (!isset($_SESSION['user_id'])) {
    header('Location: index.php');
    exit;
}

if ($_SERVER['REQUEST_METHOD'] == 'POST') {
    $item = $_POST['item'];
    $stmt = $pdo->prepare('INSERT INTO items (user_id, item) VALUES (?, ?)');
    $stmt->execute([$_SESSION['user_id'], $item]);
}

$stmt = $pdo->prepare('SELECT * FROM items WHERE user_id = ?');
$stmt->execute([$_SESSION['user_id']]);
$items = $stmt->fetchAll();
?>

<!DOCTYPE html>
<html>
<head>
    <title>Dashboard</title>
</head>
<body>
    <h1>Dashboard</h1>
    <form method="POST">
        <input type="text" name="item" required placeholder="New Item">
        <button type="submit">Add Item</button>
    </form>
    <h2>Your Items</h2>
    <ul>
        <?php foreach ($items as $item): ?>
            <li><?= htmlspecialchars($item['item']) ?></li>
        <?php endforeach; ?>
    </ul>
    <p><a href="logout.php">Logout</a></p>
</body>
</html>

